public class CustomConfigLoader extends JsonDataLoader {
    private static final Gson GSON = new GsonBuilder().setPrettyPrinting().create();
    private Map<Identifier, CustomConfig> configs = new HashMap<>();

    public CustomConfigLoader() {
        super(GSON, "custom_config");
    }

    @Override
    protected void apply(Map<Identifier, JsonElement> prepared, ResourceManager manager, Profiler profiler) {
        configs.clear();
        prepared.forEach((id, json) -> {
            CustomConfig config = GSON.fromJson(json, CustomConfig.class);
            configs.put(id, config);
        });
    }
}

public class DynamicItemRegistry {
    private static final Map<Identifier, Item> DYNAMIC_ITEMS = new HashMap<>();

    public static void registerItem(Identifier id, Item item) {
        DYNAMIC_ITEMS.put(id, item);
        Registry.register(Registries.ITEM, id, item);
    }

    public static void unregisterItem(Identifier id) {
        DYNAMIC_ITEMS.remove(id);
    }
}

public class ReloadableRecipeManager {
    private static RecipeManager customRecipeManager;

    public static void reloadRecipes(ResourceManager manager) {
        customRecipeManager = new RecipeManager();
        // 加载自定义配方
    }

    public static Optional<Recipe<?>> getRecipe(Identifier id) {
        return customRecipeManager != null ? customRecipeManager.get(id) : Optional.empty();
    }
}

public class DynamicLanguageManager {
    public static void addTranslation(String key, String value) {
        Language language = Language.getInstance();
        if (language instanceof TranslatableLanguage translatable) {
            translatable.addTranslation(key, value);
        }
    }

    public static void reloadLanguage() {
        MinecraftClient.getInstance().reloadResources();
    }
}

public class ConfigWatcher {
    private static WatchService watchService;
    private static final Map<Path, Consumer<Path>> watchers = new HashMap<>();

    public static void watchConfig(Path configPath, Consumer<Path> onChange) throws IOException {
        watchers.put(configPath, onChange);
        if (watchService == null) {
            watchService = FileSystems.getDefault().newWatchService();
            startWatching();
        }
        configPath.getParent().register(watchService, StandardWatchEventKinds.ENTRY_MODIFY);
    }
}

public class ReloadCommand {
    public static void register(CommandDispatcher<ServerCommandSource> dispatcher) {
        dispatcher.register(literal("reloadcustom")
            .requires(source -> source.hasPermissionLevel(2))
            .executes(context -> {
                ServerCommandSource source = context.getSource();
                source.getServer().reloadResources();
                source.sendFeedback(() -> Text.literal("自定义资源已重载"), true);
                return 1;
            }));
    }
}
